import { useState } from 'react';
// import {BrowserRouter as Router, Routes, Route} from 'react-router-dom'
import axios from 'axios';
// import Home from '../pages/Home'
import '../App.css';

const api = axios.create({baseURL: 'http://localhost:5000'});

function Login() {
  const [form, setForm] = useState({ login: '', password: '' });
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');
  const [messageType, setMessageType] = useState('');
  const navigate = useNavigate();

  // Автоматический вход при загрузке страницы (опционально)
  useEffect(() => {
    // Если хотите автоматический вход с тестовыми данными
    // autoLogin('admin', 'admin123');
  }, []);

  const autoLogin = async (login, password) => {
    setLoading(true);
    try {
      const response = await api.post('/login', { login, password });
      if (response.status === 200) {
        navigate('/dashboard');
      }
    } catch (error) {
      console.log('Автовход не удался');
    } finally {
      setLoading(false);
    }
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');
    setMessageType('');

    try {
      const response = await api.post('/login', form);

      if (response.status === 200) {
        setMessage(`✅ ${response.data.message}`);
        setMessageType('success');

        // Перенаправляем на dashboard после успешного входа
        setTimeout(() => {
          navigate('/dashboard');
        }, 1000);
      }
    } catch (error) {
      if (error.response) {
        setMessage(`❌ ${error.response.data.message}`);
      } else {
        setMessage('❌ Ошибка соединения с сервером');
      }
      setMessageType('error');
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
  };

  return (
    <div className="login-container">
      <div className="login-card">
        <div className="login-header">
          <h1 className="login-title">Вход в систему</h1>
          <p className="login-subtitle">Введите учетные данные</p>
        </div>

        {message && (
          <div className={`login-message ${messageType}`}>
            {message}
          </div>
        )}

        <form onSubmit={handleLogin} className="login-form">
          <div className="form-group">
            <label className="form-label">Логин</label>
            <input
              type="text"
              name="login"
              value={form.login}
              onChange={handleInputChange}
              className="form-input"
              placeholder="Введите логин"
              required
              disabled={loading}
              autoComplete="username"
            />
          </div>

          <div className="form-group">
            <label className="form-label">Пароль</label>
            <input
              type="password"
              name="password"
              value={form.password}
              onChange={handleInputChange}
              className="form-input"
              placeholder="Введите пароль"
              required
              disabled={loading}
              autoComplete="current-password"
            />
          </div>

          <button 
            type="submit" 
            className="login-button"
            disabled={loading || !form.login || !form.password}
          >
            {loading ? (
              <>
                <span className="spinner"></span>
                Вход...
              </>
            ) : 'Войти'}
          </button>
        </form>

        <div className="login-info">
          <p><strong>Тестовые данные:</strong></p>
          <p>Логин: <code>admin</code></p>
          <p>Пароль: <code>admin123</code></p>
          <p style={{ marginTop: '10px', fontSize: '12px', color: '#666' }}>
            После входа вы будете перенаправлены на /dashboard
          </p>
        </div>
      </div>
    </div>
  );
}

export default Login;
